const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const helmet = require('helmet'); // For security headers
const cors = require('cors'); // For cross-origin resource sharing

const app = express();
app.use(helmet()); // Security headers
app.use(cors()); // CORS configuration
app.use(bodyParser.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/userInputDB', { useNewUrlParser: true, useUnifiedTopology: true });

// Define a schema and model
const userInputSchema = new mongoose.Schema({
    name: String,
    email: String,
    message: String,
    timestamp: { type: Date, default: Date.now }
});

const UserInput = mongoose.model('UserInput', userInputSchema);

// Middleware to validate and sanitize input
function validateInput(req, res, next) {
    const { name, email, message } = req.body;

    if (!name || !email || !message) {
        return res.status(400).json({ error: 'All fields are required' });
    }

    if (!/\S+@\S+\.\S+/.test(email)) {
        return res.status(400).json({ error: 'Invalid email format' });
    }

    next();
}

// Route to handle form submission
app.post('/submit-form', validateInput, async (req, res) => {
    try {
        const { name, email, message } = req.body;
        const userInput = new UserInput({ name, email, message });
        await userInput.save();
        res.status(200).json({ message: 'Data saved successfully' });
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Route to retrieve past submissions
app.get('/past-submissions', async (req, res) => {
    try {
        const submissions = await UserInput.find().sort({ timestamp: -1 });
        res.json(submissions);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Start the server
